const htmlContent = "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>PPFG Interpolator — Corva-Style</title>\r\n<script src=\"https://cdn.jsdelivr.net/npm/xlsx@0.18.5/dist/xlsx.full.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js\"></script>\r\n<link href=\"https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap\" rel=\"stylesheet\">\r\n<style>\r\n:root {\r\n  --bg: #14161e;\r\n  --bg-deep: #0e1017;\r\n  --surface: #1c1f2e;\r\n  --surface2: #252839;\r\n  --surface3: #2e3248;\r\n  --border: #353950;\r\n  --border-light: #444966;\r\n  --accent: #03dac6;\r\n  --accent-dim: rgba(3,218,198,.10);\r\n  --accent-glow: rgba(3,218,198,.25);\r\n  --blue: #5b8def;\r\n  --blue-dim: rgba(91,141,239,.12);\r\n  --green: #4caf50;\r\n  --green-dim: rgba(76,175,80,.10);\r\n  --orange: #ff9800;\r\n  --orange-dim: rgba(255,152,0,.10);\r\n  --red: #ef5350;\r\n  --red-dim: rgba(239,83,80,.10);\r\n  --purple: #b388ff;\r\n  --purple-dim: rgba(179,136,255,.10);\r\n  --yellow: #fdd835;\r\n  --text: #e8eaf6;\r\n  --text-secondary: #9fa8c7;\r\n  --muted: #6b7394;\r\n  --dim: #4a5070;\r\n  --r: 10px;\r\n  --r-sm: 6px;\r\n  --shadow: 0 2px 8px rgba(0,0,0,.3);\r\n  --shadow-lg: 0 8px 32px rgba(0,0,0,.4);\r\n}\r\n*{margin:0;padding:0;box-sizing:border-box}\r\nbody{font-family:'Inter',system-ui,-apple-system,sans-serif;background:var(--bg);color:var(--text);line-height:1.5;-webkit-font-smoothing:antialiased}\r\n\r\n/* ── Top Nav ── */\r\n.topnav{background:var(--bg-deep);border-bottom:1px solid var(--border);padding:0 24px;display:flex;align-items:center;height:52px;gap:16px}\r\n.topnav .logo{display:flex;align-items:center;gap:10px}\r\n.topnav .logo-icon{width:28px;height:28px;border-radius:6px;background:linear-gradient(135deg,var(--accent),#03a896);display:flex;align-items:center;justify-content:center;font-weight:800;font-size:14px;color:var(--bg-deep)}\r\n.topnav .logo-text{font-size:15px;font-weight:700;color:var(--text);letter-spacing:-.2px}\r\n.topnav .logo-tag{font-size:11px;color:var(--muted);font-weight:500;margin-left:4px;padding:2px 8px;background:var(--surface2);border-radius:20px}\r\n.topnav .nav-sep{width:1px;height:24px;background:var(--border)}\r\n.topnav .nav-item{color:var(--muted);font-size:13px;font-weight:500;cursor:default;padding:4px 10px;border-radius:6px;transition:.15s}\r\n.topnav .nav-item:hover{color:var(--text);background:var(--surface)}\r\n.topnav .nav-item.active{color:var(--accent)}\r\n.topnav .spacer{flex:1}\r\n.topnav .status{display:flex;align-items:center;gap:6px;font-size:12px;color:var(--muted)}\r\n.topnav .status .dot{width:7px;height:7px;border-radius:50%;background:var(--green)}\r\n\r\n/* ── Steps ribbon ── */\r\n.steps-ribbon{background:var(--surface);border-bottom:1px solid var(--border);padding:0 24px;display:flex;gap:0;overflow-x:auto}\r\n.step-pill{display:flex;align-items:center;gap:8px;padding:12px 20px;font-size:12.5px;font-weight:600;color:var(--dim);cursor:default;position:relative;white-space:nowrap;transition:.15s}\r\n.step-pill .s-num{width:22px;height:22px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;border:1.5px solid var(--border);color:var(--dim);transition:.15s}\r\n.step-pill.done .s-num{background:var(--green-dim);border-color:var(--green);color:var(--green)}\r\n.step-pill.done{color:var(--green)}\r\n.step-pill.active .s-num{background:var(--accent-dim);border-color:var(--accent);color:var(--accent)}\r\n.step-pill.active{color:var(--text)}\r\n.step-pill.active::after{content:'';position:absolute;bottom:0;left:12px;right:12px;height:2px;background:var(--accent);border-radius:2px 2px 0 0}\r\n.step-pill .s-check{display:none;font-size:13px;color:var(--green)}\r\n.step-pill.done .s-check{display:inline}\r\n.step-pill.done .s-num{display:none}\r\n\r\n/* ── Layout ── */\r\n.app-body{display:flex;min-height:calc(100vh - 104px)}\r\n.sidebar{width:360px;min-width:360px;background:var(--surface);border-right:1px solid var(--border);display:flex;flex-direction:column;overflow-y:auto;max-height:calc(100vh - 104px)}\r\n.sidebar-section{padding:18px 20px;border-bottom:1px solid var(--border)}\r\n.sidebar-section:last-child{border-bottom:none}\r\n.main-content{flex:1;padding:20px;overflow-y:auto;max-height:calc(100vh - 104px);background:var(--bg)}\r\n\r\n/* ── Section titles ── */\r\n.sec-title{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:var(--accent);margin-bottom:12px;display:flex;align-items:center;gap:8px}\r\n.sec-title .sec-icon{font-size:14px}\r\n\r\n/* ── Upload zone ── */\r\n.upload-zone{border:1.5px dashed var(--border);border-radius:var(--r);padding:22px 14px;text-align:center;cursor:pointer;transition:.2s;background:var(--bg)}\r\n.upload-zone:hover,.upload-zone.dragover{border-color:var(--accent);background:var(--accent-dim)}\r\n.upload-zone.loaded{border-color:var(--green);border-style:solid;background:var(--green-dim)}\r\n.upload-zone input[type=file]{display:none}\r\n.upload-zone .uz-icon{font-size:28px;margin-bottom:2px;opacity:.6}\r\n.upload-zone .uz-text{font-size:12px;color:var(--muted)}\r\n.upload-zone .uz-file{font-size:12px;color:var(--green);margin-top:4px;font-weight:600;word-break:break-all}\r\n\r\n/* ── Form controls ── */\r\nlabel.ctrl-label{display:block;font-size:11px;color:var(--muted);margin-bottom:3px;font-weight:600;text-transform:uppercase;letter-spacing:.04em}\r\nselect,input[type=number],input[type=text],input[type=password]{width:100%;background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--r-sm);padding:8px 10px;color:var(--text);font-size:13px;font-family:inherit;margin-bottom:8px;outline:none;transition:.15s}\r\nselect:focus,input:focus{border-color:var(--accent);box-shadow:0 0 0 2px var(--accent-dim)}\r\n\r\n/* ── Buttons ── */\r\n.btn{display:inline-flex;align-items:center;gap:6px;padding:9px 18px;border-radius:var(--r-sm);border:none;font-size:13px;font-weight:600;font-family:inherit;cursor:pointer;transition:.12s;letter-spacing:-.1px}\r\n.btn-primary{background:var(--accent);color:var(--bg-deep)}\r\n.btn-primary:hover{background:#00f0d6;box-shadow:0 0 16px var(--accent-glow)}\r\n.btn-primary:disabled{opacity:.3;cursor:not-allowed;box-shadow:none}\r\n.btn-green{background:var(--green);color:#fff}\r\n.btn-green:hover{background:#43a047}\r\n.btn-outline{background:transparent;border:1px solid var(--border);color:var(--text)}\r\n.btn-outline:hover{background:var(--surface2);border-color:var(--border-light)}\r\n.btn-orange{background:var(--orange);color:var(--bg-deep)}\r\n.btn-orange:hover{background:#ffa726}\r\n.btn-blue{background:var(--blue);color:#fff}\r\n.btn-blue:hover{background:#6f9ef3;box-shadow:0 0 16px var(--blue-dim)}\r\n.btn-blue:disabled{opacity:.3;cursor:not-allowed;box-shadow:none}\r\n.btn-sm{padding:6px 12px;font-size:11.5px}\r\n.btn-block{width:100%}\r\n\r\n/* ── KPI cards ── */\r\n.kpi-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:6px;margin-top:10px}\r\n.kpi{background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--r-sm);padding:8px;text-align:center}\r\n.kpi .kv{font-size:14px;font-weight:700;font-variant-numeric:tabular-nums}\r\n.kpi .kl{font-size:10px;color:var(--muted);margin-top:1px;text-transform:uppercase;letter-spacing:.04em}\r\n\r\n/* ── Mapping row ── */\r\n.mrow{margin-bottom:6px}\r\n\r\n/* ── Main tabs ── */\r\n.main-tabs{display:flex;gap:2px;margin-bottom:16px;background:var(--surface);border-radius:var(--r);padding:3px;border:1px solid var(--border)}\r\n.main-tab{flex:1;padding:9px 10px;text-align:center;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;color:var(--dim);border:none;background:none;font-family:inherit;transition:.12s}\r\n.main-tab.on{background:var(--accent);color:var(--bg-deep)}\r\n.main-tab:not(.on):hover{color:var(--text);background:var(--surface2)}\r\n.tpane{display:none}\r\n.tpane.on{display:block}\r\n\r\n/* ── Table ── */\r\ntable{width:100%;border-collapse:collapse;font-size:12px}\r\nth{background:var(--surface2);padding:9px 10px;text-align:left;font-weight:700;font-size:10.5px;text-transform:uppercase;letter-spacing:.04em;color:var(--muted);border-bottom:1px solid var(--border);position:sticky;top:0;z-index:2}\r\ntd{padding:6px 10px;border-bottom:1px solid rgba(53,57,80,.4);font-variant-numeric:tabular-nums}\r\ntr:hover td{background:rgba(3,218,198,.02)}\r\n.twrap{overflow:auto;border:1px solid var(--border);border-radius:var(--r);box-shadow:var(--shadow)}\r\n.c-md{color:var(--blue)}\r\n.c-tvd{color:var(--accent)}\r\n.c-inc{color:var(--orange)}\r\n.c-pp{color:var(--purple)}\r\n.c-fg{color:var(--yellow)}\r\n\r\n/* ── Chart container ── */\r\n.chart-container{position:relative;height:500px;background:var(--surface);border:1px solid var(--border);border-radius:var(--r);padding:12px;box-shadow:var(--shadow)}\r\n\r\n/* ── Toolbar ── */\r\n.toolbar{display:flex;gap:8px;margin-bottom:12px;align-items:center;flex-wrap:wrap}\r\n.toolbar .spacer{flex:1}\r\n.chip{display:inline-flex;align-items:center;gap:4px;padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700}\r\n.chip-accent{background:var(--accent-dim);color:var(--accent)}\r\n.chip-green{background:var(--green-dim);color:var(--green)}\r\n.chip-blue{background:var(--blue-dim);color:var(--blue)}\r\n.chip-purple{background:var(--purple-dim);color:var(--purple)}\r\n\r\n/* ── Empty state ── */\r\n.empty-state{text-align:center;padding:80px 24px;color:var(--dim)}\r\n.empty-state .es-icon{font-size:48px;margin-bottom:8px;opacity:.3}\r\n.empty-state p{font-size:13px}\r\n\r\n/* ── Quick calc ── */\r\n.calc-row{display:flex;gap:8px;align-items:flex-end}\r\n.calc-row>div{flex:1}\r\n.calc-row .btn{margin-bottom:0;white-space:nowrap}\r\n.res-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:12px}\r\n.res-box{background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--r-sm);padding:12px;text-align:center}\r\n.res-box .rv{font-size:22px;font-weight:700;margin:2px 0}\r\n.res-box .ru{color:var(--muted);font-size:11px}\r\n.res-box .rl{color:var(--dim);font-size:10px;text-transform:uppercase;letter-spacing:.04em}\r\n.formula-box{background:var(--bg-deep);border:1px solid var(--border);border-radius:var(--r-sm);padding:12px 14px;font-family:'JetBrains Mono','Fira Code','Consolas',monospace;font-size:12px;color:var(--accent);margin-top:8px;line-height:1.8}\r\n.station-info{background:var(--bg-deep);border-radius:var(--r-sm);padding:8px 12px;margin-top:8px;font-size:12px;color:var(--muted)}\r\n.station-info strong{color:var(--text)}\r\n\r\n/* ── Toast ── */\r\n.toast{position:fixed;bottom:24px;right:24px;background:var(--surface2);border:1px solid var(--accent);color:var(--accent);padding:12px 20px;border-radius:var(--r);font-size:13px;font-weight:600;z-index:200;transform:translateY(80px);opacity:0;transition:.3s;box-shadow:var(--shadow-lg)}\r\n.toast.on{transform:translateY(0);opacity:1}\r\n.toast.err{border-color:var(--red);color:var(--red)}\r\n\r\n/* ── PPFG Column chips in table header ── */\r\nth.th-pp{color:var(--purple)}\r\nth.th-fg{color:var(--yellow)}\r\n\r\n/* ── Units sub-header row ── */\r\ntr.units-row th{background:var(--surface);font-size:9.5px;font-weight:500;font-style:italic;color:var(--dim);padding:4px 10px;text-transform:none;letter-spacing:0;border-bottom:2px solid var(--border)}\r\n\r\n/* ── Responsive ── */\r\n@media(max-width:960px){\r\n  .app-body{flex-direction:column}\r\n  .sidebar{width:100%;min-width:0;max-height:none;border-right:none;border-bottom:1px solid var(--border)}\r\n  .main-content{max-height:none}\r\n}\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<!-- ═══ TOP NAVIGATION ═══ -->\r\n<nav class=\"topnav\">\r\n  <div class=\"logo\">\r\n    <div class=\"logo-icon\">P</div>\r\n    <span class=\"logo-text\">PPFG Interpolator</span>\r\n    <span class=\"logo-tag\">v2.0</span>\r\n  </div>\r\n  <div class=\"nav-sep\"></div>\r\n  <span class=\"nav-item active\">Well Plan &amp; PPFG</span>\r\n  <span class=\"spacer\"></span>\r\n  <div class=\"status\"><div class=\"dot\" id=\"statusDot\" style=\"background:var(--dim)\"></div><span id=\"statusText\">No data loaded</span></div>\r\n</nav>\r\n\r\n<!-- ═══ STEPS RIBBON ═══ -->\r\n<div class=\"steps-ribbon\" id=\"stepsRibbon\">\r\n  <div class=\"step-pill active\" id=\"step1\"><span class=\"s-num\">1</span><span class=\"s-check\">&#10003;</span> Well Plan</div>\r\n  <div class=\"step-pill\" id=\"step2\"><span class=\"s-num\">2</span><span class=\"s-check\">&#10003;</span> PPFG Document</div>\r\n  <div class=\"step-pill\" id=\"step3\"><span class=\"s-num\">3</span><span class=\"s-check\">&#10003;</span> Interpolate</div>\r\n</div>\r\n\r\n<div class=\"app-body\">\r\n<!-- ═══ SIDEBAR ═══ -->\r\n<div class=\"sidebar\">\r\n\r\n  <!-- STEP 1: Well Plan -->\r\n  <div class=\"sidebar-section\">\r\n    <div class=\"sec-title\"><span class=\"sec-icon\">&#9883;</span> Step 1 — Well Plan / Survey</div>\r\n    <div class=\"upload-zone\" id=\"zSurvey\" onclick=\"document.getElementById('fSurvey').click()\">\r\n      <input type=\"file\" id=\"fSurvey\" accept=\".xlsx,.xls,.csv\">\r\n      <div class=\"uz-icon\">&#128209;</div>\r\n      <div class=\"uz-text\">Drop well plan Excel / CSV here</div>\r\n      <div class=\"uz-file\" id=\"fnSurvey\"></div>\r\n    </div>\r\n    <div id=\"mapSurvey\" style=\"display:none;margin-top:12px\">\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">Sheet</label><select id=\"sSheet\" onchange=\"onSheetChange()\"></select></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">Header Row</label><input type=\"number\" id=\"sHdr\" value=\"1\" min=\"1\" max=\"100\" onchange=\"onSheetChange()\"></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">MD Column</label><select id=\"cMD\"></select></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">Inclination Column</label><select id=\"cInc\"></select></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">Azimuth Column (optional)</label><select id=\"cAzm\"></select></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">TVD Column</label><select id=\"cTVD\"></select></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">Depth Unit</label><select id=\"sSurveyUnit\"><option value=\"ft\">Feet (ft)</option><option value=\"m\">Meters (m)</option></select></div>\r\n      <button class=\"btn btn-primary btn-block\" onclick=\"loadSurvey()\">Load Survey</button>\r\n    </div>\r\n    <div id=\"surveyOk\" style=\"display:none\">\r\n      <div class=\"kpi-grid\">\r\n        <div class=\"kpi\"><div class=\"kv\" id=\"xN\">-</div><div class=\"kl\">Stations</div></div>\r\n        <div class=\"kpi\"><div class=\"kv\" id=\"xMD\">-</div><div class=\"kl\">Max MD</div></div>\r\n        <div class=\"kpi\"><div class=\"kv\" id=\"xTVD\">-</div><div class=\"kl\">Max TVD</div></div>\r\n        <div class=\"kpi\"><div class=\"kv\" id=\"xInc\">-</div><div class=\"kl\">Max Inc</div></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- STEP 2: PPFG Document -->\r\n  <div class=\"sidebar-section\">\r\n    <div class=\"sec-title\"><span class=\"sec-icon\">&#128202;</span> Step 2 — PPFG Document</div>\r\n    <div class=\"upload-zone\" id=\"zPpfg\" onclick=\"document.getElementById('fPpfg').click()\">\r\n      <input type=\"file\" id=\"fPpfg\" accept=\".xlsx,.xls,.csv,.txt\">\r\n      <div class=\"uz-icon\">&#128200;</div>\r\n      <div class=\"uz-text\">Drop PPFG Excel / CSV here</div>\r\n      <div class=\"uz-file\" id=\"fnPpfg\"></div>\r\n    </div>\r\n    <div id=\"mapPpfg\" style=\"display:none;margin-top:12px\">\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">Sheet</label><select id=\"pSheet\" onchange=\"onPpfgSheetChange()\"></select></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">Header Row</label><input type=\"number\" id=\"pHdr\" value=\"1\" min=\"1\" max=\"100\" onchange=\"onPpfgSheetChange()\"></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">TVD Column</label><select id=\"pTvdCol\"></select></div>\r\n      <div class=\"mrow\"><label class=\"ctrl-label\">Depth Unit</label><select id=\"sPpfgUnit\"><option value=\"ft\">Feet (ft)</option><option value=\"m\">Meters (m)</option></select></div>\r\n      <div id=\"ppfgColList\" style=\"margin-top:8px\"></div>\r\n      <button class=\"btn btn-green btn-block\" style=\"margin-top:8px\" onclick=\"loadPpfgData()\">Load PPFG Data</button>\r\n    </div>\r\n    <div id=\"ppfgOk\" style=\"display:none\">\r\n      <div class=\"kpi-grid\" style=\"grid-template-columns:repeat(3,1fr)\">\r\n        <div class=\"kpi\"><div class=\"kv\" id=\"xPRows\">-</div><div class=\"kl\">Rows</div></div>\r\n        <div class=\"kpi\"><div class=\"kv\" id=\"xPCols\">-</div><div class=\"kl\">Curves</div></div>\r\n        <div class=\"kpi\"><div class=\"kv\" id=\"xPRange\">-</div><div class=\"kl\">TVD Range</div></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- STEP 3: Interpolate -->\r\n  <div class=\"sidebar-section\">\r\n    <div class=\"sec-title\"><span class=\"sec-icon\">&#9881;</span> Step 3 — Interpolate MDs</div>\r\n    <button class=\"btn btn-primary btn-block\" id=\"btnInterp\" onclick=\"runInterpolation()\" disabled>Interpolate Measured Depths</button>\r\n    <div id=\"interpOk\" style=\"display:none;margin-top:10px\">\r\n      <div class=\"kpi-grid\" style=\"grid-template-columns:repeat(2,1fr)\">\r\n        <div class=\"kpi\"><div class=\"kv c-tvd\" id=\"xIRows\">-</div><div class=\"kl\">Depths</div></div>\r\n        <div class=\"kpi\"><div class=\"kv c-md\" id=\"xIMDR\">-</div><div class=\"kl\">MD Range</div></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Quick Lookup -->\r\n  <div class=\"sidebar-section\">\r\n    <div class=\"sec-title\"><span class=\"sec-icon\">&#128269;</span> Quick TVD &rarr; MD Lookup</div>\r\n    <div class=\"calc-row\">\r\n      <div>\r\n        <label class=\"ctrl-label\">TVD (ft)</label>\r\n        <input type=\"number\" id=\"qIn\" step=\"any\" placeholder=\"e.g. 14000\" style=\"margin:0\">\r\n      </div>\r\n      <button class=\"btn btn-primary btn-sm\" onclick=\"calcOne()\" style=\"margin-bottom:0\">Calc</button>\r\n    </div>\r\n    <div id=\"qOut\" style=\"display:none\">\r\n      <div class=\"res-grid\">\r\n        <div class=\"res-box\"><div class=\"rl\">Interp. MD</div><div class=\"rv c-md\" id=\"qMD\">-</div><div class=\"ru\">ft</div></div>\r\n        <div class=\"res-box\"><div class=\"rl\">Station Inc</div><div class=\"rv c-inc\" id=\"qInc\">-</div><div class=\"ru\">deg</div></div>\r\n      </div>\r\n      <div class=\"station-info\" id=\"qStn\"></div>\r\n      <div class=\"formula-box\" id=\"qForm\"></div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Upload to Corva -->\r\n  <div class=\"sidebar-section\">\r\n    <div class=\"sec-title\"><span class=\"sec-icon\">&#9729;</span> Upload to Corva</div>\r\n    <div class=\"mrow\"><label class=\"ctrl-label\">Export File Name</label><input type=\"text\" id=\"corvaFileName\" value=\"ppfg_interpolated\" placeholder=\"ppfg_interpolated\"></div>\r\n    <div class=\"mrow\"><label class=\"ctrl-label\">Well Asset ID</label><input type=\"number\" id=\"corvaAssetId\" placeholder=\"e.g. 43550142\"></div>\r\n    <div class=\"mrow\"><label class=\"ctrl-label\">Log Identifier</label><input type=\"text\" id=\"corvaLogId\" value=\"ppfg_interpolated\" placeholder=\"ppfg_interpolated\"></div>\r\n    <div class=\"mrow\"><label class=\"ctrl-label\">Provider</label><input type=\"text\" id=\"corvaProvider\" value=\"corva\" placeholder=\"corva\"></div>\r\n    <div class=\"mrow\"><label class=\"ctrl-label\">Dataset</label><input type=\"text\" id=\"corvaDataset\" value=\"drilling.wits.depth\" placeholder=\"drilling.wits.depth\"></div>\r\n    <button class=\"btn btn-blue btn-block\" id=\"btnUploadCorva\" onclick=\"uploadToCorva()\" disabled>Upload to Corva Logs</button>\r\n    <div id=\"corvaUploadStatus\" style=\"display:none;margin-top:8px\">\r\n      <div class=\"kpi-grid\" style=\"grid-template-columns:repeat(2,1fr)\">\r\n        <div class=\"kpi\"><div class=\"kv c-tvd\" id=\"xUpRows\">-</div><div class=\"kl\">Records</div></div>\r\n        <div class=\"kpi\"><div class=\"kv c-md\" id=\"xUpStatus\">-</div><div class=\"kl\">Status</div></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n</div>\r\n\r\n<!-- ═══ MAIN CONTENT ═══ -->\r\n<div class=\"main-content\">\r\n  <div class=\"main-tabs\">\r\n    <button class=\"main-tab on\" onclick=\"goTab('pChart')\">Well Profile</button>\r\n    <button class=\"main-tab\" onclick=\"goTab('pSurvey')\">Survey Table</button>\r\n    <button class=\"main-tab\" onclick=\"goTab('pPpfg')\">PPFG Data</button>\r\n    <button class=\"main-tab\" onclick=\"goTab('pResults')\">Export Results</button>\r\n  </div>\r\n\r\n  <!-- Well Profile Chart -->\r\n  <div id=\"pChart\" class=\"tpane on\">\r\n    <div id=\"eChart\" class=\"empty-state\"><div class=\"es-icon\">&#128200;</div><p>Load a well plan to view the MD vs TVD profile</p></div>\r\n    <div id=\"aChart\" style=\"display:none\">\r\n      <div class=\"toolbar\"><span class=\"chip chip-accent\" id=\"bChart\">-</span><span class=\"spacer\"></span></div>\r\n      <div class=\"chart-container\"><canvas id=\"cvs\"></canvas></div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Survey Table -->\r\n  <div id=\"pSurvey\" class=\"tpane\">\r\n    <div id=\"eSurvey\" class=\"empty-state\"><div class=\"es-icon\">&#128203;</div><p>No survey loaded yet</p></div>\r\n    <div id=\"aSurvey\" style=\"display:none\">\r\n      <div class=\"toolbar\">\r\n        <span class=\"chip chip-accent\" id=\"bSurvey\">-</span><span class=\"spacer\"></span>\r\n        <button class=\"btn btn-outline btn-sm\" onclick=\"expSurveyCSV()\">Export CSV</button>\r\n      </div>\r\n      <div class=\"twrap\" style=\"max-height:calc(100vh - 260px)\">\r\n        <table><thead>\r\n          <tr><th>#</th><th>MD</th><th>Inc</th><th>Azm</th><th>TVD</th></tr>\r\n          <tr class=\"units-row\"><th></th><th>FT</th><th>deg</th><th>deg</th><th>FT</th></tr>\r\n        </thead>\r\n        <tbody id=\"tbSurvey\"></tbody></table>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- PPFG Data -->\r\n  <div id=\"pPpfg\" class=\"tpane\">\r\n    <div id=\"ePpfg\" class=\"empty-state\"><div class=\"es-icon\">&#128202;</div><p>Import a PPFG document to view pressure &amp; gradient data</p></div>\r\n    <div id=\"aPpfg\" style=\"display:none\">\r\n      <div class=\"toolbar\">\r\n        <span class=\"chip chip-purple\" id=\"bPpfg\">-</span><span class=\"spacer\"></span>\r\n        <button class=\"btn btn-outline btn-sm\" onclick=\"expPpfgCSV()\">Export PPFG CSV</button>\r\n      </div>\r\n      <!-- Sub-tabs: table and chart -->\r\n      <div class=\"main-tabs\" style=\"margin-bottom:12px\">\r\n        <button class=\"main-tab on\" onclick=\"goPpfgSub('ppfgTable')\">Data Table</button>\r\n        <button class=\"main-tab\" onclick=\"goPpfgSub('ppfgChart')\">Pressure Plot</button>\r\n      </div>\r\n      <div id=\"ppfgTable\" class=\"tpane on\">\r\n        <div class=\"twrap\" style=\"max-height:calc(100vh - 340px)\">\r\n          <table id=\"tblPpfg\"><thead id=\"thPpfg\"></thead><tbody id=\"tbPpfg\"></tbody></table>\r\n        </div>\r\n      </div>\r\n      <div id=\"ppfgChart\" class=\"tpane\">\r\n        <div class=\"chart-container\" style=\"height:550px\"><canvas id=\"cvsPpfg\"></canvas></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Export Results -->\r\n  <div id=\"pResults\" class=\"tpane\">\r\n    <div id=\"eResults\" class=\"empty-state\"><div class=\"es-icon\">&#128290;</div><p>Complete all 3 steps to see interpolation results</p></div>\r\n    <div id=\"aResults\" style=\"display:none\">\r\n      <div class=\"toolbar\">\r\n        <span class=\"chip chip-green\" id=\"bResults\">-</span><span class=\"spacer\"></span>\r\n        <button class=\"btn btn-outline btn-sm\" onclick=\"expResultsCSV()\">Export CSV</button>\r\n        <button class=\"btn btn-orange btn-sm\" onclick=\"expResultsXLSX()\">Export Excel</button>\r\n      </div>\r\n      <div class=\"twrap\" style=\"max-height:calc(100vh - 260px)\">\r\n        <table id=\"tblResults\"><thead id=\"thResults\"></thead><tbody id=\"tbResults\"></tbody></table>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>\r\n</div>\r\n\r\n<div class=\"toast\" id=\"toast\"></div>\r\n\r\n<script>\r\n/* ═══════════════════════════════════════════\r\n   State\r\n   ═══════════════════════════════════════════ */\r\nlet survey = [];\r\nlet surveyByMD = [];\r\nlet ppfgData = [];\r\nlet ppfgCols = [];\r\nlet ppfgTvdUnit = 'FT';\r\nlet results = [];\r\nlet wbSurvey = null;\r\nlet wbPpfg = null;\r\nlet chart = null;\r\nlet ppfgChart = null;\r\n\r\n/* ═══════════════════════════════════════════\r\n   File Upload Wiring\r\n   ═══════════════════════════════════════════ */\r\nfunction wire(zoneId, inputId, cb) {\r\n  const z = document.getElementById(zoneId);\r\n  const f = document.getElementById(inputId);\r\n  z.addEventListener('dragover', e => { e.preventDefault(); z.classList.add('dragover'); });\r\n  z.addEventListener('dragleave', () => z.classList.remove('dragover'));\r\n  z.addEventListener('drop', e => {\r\n    e.preventDefault(); z.classList.remove('dragover');\r\n    if (e.dataTransfer.files.length) { f.files = e.dataTransfer.files; cb(e.dataTransfer.files[0]); }\r\n  });\r\n  f.addEventListener('change', () => { if (f.files.length) cb(f.files[0]); });\r\n}\r\nwire('zSurvey', 'fSurvey', onSurveyFile);\r\nwire('zPpfg', 'fPpfg', onPpfgFile);\r\n\r\nfunction readFile(file, cb) {\r\n  const r = new FileReader();\r\n  const isCSV = /\\.(csv|txt)$/i.test(file.name);\r\n  r.onload = e => {\r\n    const wb = isCSV\r\n      ? XLSX.read(e.target.result, { type: 'string' })\r\n      : XLSX.read(e.target.result, { type: 'array' });\r\n    cb(wb);\r\n  };\r\n  isCSV ? r.readAsText(file) : r.readAsArrayBuffer(file);\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Step 1: Well Plan\r\n   ═══════════════════════════════════════════ */\r\nfunction onSurveyFile(file) {\r\n  document.getElementById('fnSurvey').textContent = file.name;\r\n  document.getElementById('zSurvey').classList.add('loaded');\r\n  readFile(file, wb => {\r\n    wbSurvey = wb;\r\n    const sel = document.getElementById('sSheet');\r\n    sel.innerHTML = wb.SheetNames.map(n => `<option>${n}</option>`).join('');\r\n    const pref = wb.SheetNames.find(n => /survey|basic|plan|100ft|traj|direct/i.test(n));\r\n    if (pref) sel.value = pref;\r\n    show('mapSurvey');\r\n    onSheetChange();\r\n  });\r\n}\r\n\r\nfunction onSheetChange() {\r\n  const { headers: hdrs } = getHeaders(wbSurvey, document.getElementById('sSheet').value, +document.getElementById('sHdr').value || 1);\r\n  fillSel('cMD', hdrs, ['md', 'measured depth', 'measured']);\r\n  fillSel('cInc', hdrs, ['inc', 'incl', 'inclination']);\r\n  fillSel('cAzm', hdrs, ['azm', 'azim', 'azimuth'], true);\r\n  fillSel('cTVD', hdrs, ['tvd', 'true vertical', 'vertical depth']);\r\n}\r\n\r\nfunction loadSurvey() {\r\n  const sh = document.getElementById('sSheet').value;\r\n  const hr = +document.getElementById('sHdr').value || 1;\r\n  const iMD = +document.getElementById('cMD').value;\r\n  const iInc = +document.getElementById('cInc').value;\r\n  const iAzm = document.getElementById('cAzm').value;\r\n  const iTVD = +document.getElementById('cTVD').value;\r\n  if (isNaN(iMD) || isNaN(iInc) || isNaN(iTVD)) { toast('Select MD, Inc, and TVD columns', true); return; }\r\n\r\n  const surveyUnit = document.getElementById('sSurveyUnit').value;\r\n  const mToFt = surveyUnit === 'm' ? 3.28084 : 1;\r\n\r\n  const ws = wbSurvey.Sheets[sh];\r\n  const rng = XLSX.utils.decode_range(ws['!ref']);\r\n  const { detectedRow } = getHeaders(wbSurvey, sh, hr);\r\n  const raw = [];\r\n  for (let r = detectedRow + 1; r <= rng.e.r; r++) {\r\n    const md = cellNum(ws, r, iMD);\r\n    const inc = cellNum(ws, r, iInc);\r\n    const azm = iAzm !== '' ? cellNum(ws, r, +iAzm) : 0;\r\n    const tvd = cellNum(ws, r, iTVD);\r\n    if (md == null || inc == null || tvd == null) continue;\r\n    raw.push({ md: md * mToFt, inc, azm: azm || 0, tvd: tvd * mToFt });\r\n  }\r\n  raw.sort((a, b) => a.md - b.md);\r\n  const seen = new Set();\r\n  surveyByMD = raw.filter(s => { if (seen.has(s.md)) return false; seen.add(s.md); return true; });\r\n  survey = [...surveyByMD].sort((a, b) => a.tvd - b.tvd);\r\n\r\n  if (survey.length < 2) { toast('Need at least 2 survey stations', true); return; }\r\n\r\n  const n = survey.length;\r\n  show('surveyOk');\r\n  document.getElementById('xN').textContent = n;\r\n  document.getElementById('xMD').textContent = fmt0(surveyByMD[surveyByMD.length - 1].md);\r\n  document.getElementById('xTVD').textContent = fmt0(survey[survey.length - 1].tvd);\r\n  document.getElementById('xInc').textContent = Math.max(...survey.map(s => s.inc)).toFixed(1) + '\\u00B0';\r\n\r\n  document.getElementById('tbSurvey').innerHTML = surveyByMD.map((s, i) =>\r\n    `<tr><td>${i+1}</td><td>${s.md.toFixed(2)}</td><td>${s.inc.toFixed(2)}</td><td>${s.azm.toFixed(2)}</td><td>${s.tvd.toFixed(3)}</td></tr>`\r\n  ).join('');\r\n  show('aSurvey'); hide('eSurvey');\r\n  document.getElementById('bSurvey').textContent = n + ' stations';\r\n\r\n  drawChart();\r\n  show('aChart'); hide('eChart');\r\n  document.getElementById('bChart').textContent = n + ' stations';\r\n\r\n  markStep(1, 'done');\r\n  markStep(2, 'active');\r\n  updateStatus('Survey loaded', true);\r\n  checkReady();\r\n  toast(`Loaded ${n} survey stations`);\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Step 2: PPFG Document\r\n   ═══════════════════════════════════════════ */\r\nfunction onPpfgFile(file) {\r\n  document.getElementById('fnPpfg').textContent = file.name;\r\n  document.getElementById('zPpfg').classList.add('loaded');\r\n  readFile(file, wb => {\r\n    wbPpfg = wb;\r\n    const sel = document.getElementById('pSheet');\r\n    sel.innerHTML = wb.SheetNames.map(n => `<option>${n}</option>`).join('');\r\n    const pref = wb.SheetNames.find(n => /dep|ppfg|pore|frac|pressure/i.test(n));\r\n    if (pref) sel.value = pref;\r\n    show('mapPpfg');\r\n    onPpfgSheetChange();\r\n  });\r\n}\r\n\r\nfunction onPpfgSheetChange() {\r\n  const { headers: hdrs } = getHeaders(wbPpfg, document.getElementById('pSheet').value, +document.getElementById('pHdr').value || 1);\r\n  fillSel('pTvdCol', hdrs, ['tvd', 'tvdkb', 'true vertical', 'vertical depth']);\r\n\r\n  const list = document.getElementById('ppfgColList');\r\n  const ppfgPatterns = ['ppg', 'fg', 'bhs', 'obg', 'pp_', 'fp_', 'seawater', 'mw', 'mud'];\r\n  const matched = hdrs.filter(h => {\r\n    const l = h.lbl.toLowerCase();\r\n    return ppfgPatterns.some(p => l.includes(p)) || /^(pp|fg|fracture|pore|gradient|overburden|mud)/i.test(l);\r\n  });\r\n\r\n  if (matched.length > 0) {\r\n    list.innerHTML = `<label class=\"ctrl-label\" style=\"margin-bottom:6px\">Detected PPFG Columns (${matched.length})</label>` +\r\n      `<div style=\"max-height:100px;overflow-y:auto;font-size:11px;color:var(--text-secondary);line-height:1.8;background:var(--bg-deep);border-radius:var(--r-sm);padding:6px 10px;border:1px solid var(--border)\">`+\r\n      matched.map(h => `<span style=\"color:var(--purple)\">${h.letter}</span>: ${h.lbl}`).join('<br>') +\r\n      `</div>`;\r\n  } else {\r\n    list.innerHTML = `<div style=\"font-size:11px;color:var(--muted);padding:4px 0\">All non-TVD numeric columns will be imported as pressure/gradient data.</div>`;\r\n  }\r\n}\r\n\r\nfunction loadPpfgData() {\r\n  const sh = document.getElementById('pSheet').value;\r\n  const hr = +document.getElementById('pHdr').value || 1;\r\n  const iTvd = +document.getElementById('pTvdCol').value;\r\n  if (isNaN(iTvd)) { toast('Select the TVD column', true); return; }\r\n\r\n  const ws = wbPpfg.Sheets[sh];\r\n  const rng = XLSX.utils.decode_range(ws['!ref']);\r\n\r\n  const { headers: allHdrs, detectedRow } = getHeaders(wbPpfg, sh, hr);\r\n  const dataAfterHdr = detectedRow + 1;\r\n\r\n  ppfgCols = [];\r\n  const usedNames = {};\r\n  for (const h of allHdrs) {\r\n    if (h.c === iTvd) continue;\r\n    const l = h.lbl.toLowerCase();\r\n    if (/unit|date|well|name|api|operator|field/i.test(l)) continue;\r\n    const parsed = parseNameUnit(h.lbl);\r\n    let colName = parsed.name;\r\n    if (usedNames[colName]) {\r\n      usedNames[colName]++;\r\n      colName = colName + '_' + usedNames[colName];\r\n    } else {\r\n      usedNames[colName] = 1;\r\n    }\r\n    ppfgCols.push({ c: h.c, name: colName, unit: parsed.unit });\r\n  }\r\n\r\n  let unitsRow = null;\r\n  const unitCheck = cellStr(ws, dataAfterHdr, iTvd);\r\n  const unitCheck2 = ppfgCols.length > 0 ? cellStr(ws, dataAfterHdr, ppfgCols[0].c) : null;\r\n  const isUnitsRow = (unitCheck && /^(ft|ppg|psi|sg|kpa|bar|m|deg|degrees)$/i.test(unitCheck.trim())) ||\r\n                     (unitCheck2 && /^(ft|ppg|psi|sg|kpa|bar|m|deg|degrees)$/i.test(unitCheck2.trim()));\r\n  if (isUnitsRow) {\r\n    unitsRow = dataAfterHdr;\r\n    ppfgTvdUnit = (cellStr(ws, dataAfterHdr, iTvd) || 'FT').trim();\r\n    for (const col of ppfgCols) {\r\n      const u = cellStr(ws, dataAfterHdr, col.c);\r\n      if (u && u.trim()) col.unit = u.trim();\r\n    }\r\n  } else {\r\n    ppfgTvdUnit = 'FT';\r\n  }\r\n\r\n  const ppfgUnit = document.getElementById('sPpfgUnit').value;\r\n  const ppfgMToFt = ppfgUnit === 'm' ? 3.28084 : 1;\r\n\r\n  ppfgData = [];\r\n  const startRow = unitsRow != null ? unitsRow + 1 : dataAfterHdr;\r\n  for (let r = startRow; r <= rng.e.r; r++) {\r\n    const rawTvd = cellNum(ws, r, iTvd);\r\n    if (rawTvd == null || rawTvd <= 0) continue;\r\n    const tvd = rawTvd * ppfgMToFt;\r\n\r\n    let hasData = false;\r\n    const row = { tvd };\r\n    for (const col of ppfgCols) {\r\n      const v = cellNum(ws, r, col.c);\r\n      row[col.name] = v;\r\n      if (v != null && v !== 0) hasData = true;\r\n    }\r\n    if (!hasData) continue;\r\n\r\n    ppfgData.push(row);\r\n  }\r\n\r\n  if (ppfgData.length === 0) { toast('No valid PPFG rows found', true); return; }\r\n\r\n  ppfgCols = ppfgCols.filter(col => ppfgData.some(r => r[col.name] != null && r[col.name] !== 0));\r\n\r\n  show('ppfgOk');\r\n  document.getElementById('xPRows').textContent = ppfgData.length;\r\n  document.getElementById('xPCols').textContent = ppfgCols.length;\r\n  const tvds = ppfgData.map(r => r.tvd);\r\n  document.getElementById('xPRange').textContent = fmt0(Math.min(...tvds)) + '–' + fmt0(Math.max(...tvds));\r\n\r\n  renderPpfgTable();\r\n  renderPpfgChart();\r\n  show('aPpfg'); hide('ePpfg');\r\n  document.getElementById('bPpfg').textContent = ppfgData.length + ' rows, ' + ppfgCols.length + ' curves';\r\n\r\n  markStep(2, 'done');\r\n  markStep(3, 'active');\r\n  updateStatus('PPFG loaded', true);\r\n  checkReady();\r\n  toast(`Loaded ${ppfgData.length} PPFG rows with ${ppfgCols.length} curves`);\r\n}\r\n\r\nfunction renderPpfgTable() {\r\n  const isPP = name => /ppg|pp_|pore|mud|mw/i.test(name);\r\n  const isFG = name => /fg|frac|lot|obg|bhs|seawater|fp_/i.test(name);\r\n\r\n  let hdrRow = '<tr><th>#</th><th>TVD</th>' +\r\n    ppfgCols.map(c => {\r\n      const cls = isPP(c.name) ? 'th-pp' : isFG(c.name) ? 'th-fg' : '';\r\n      return `<th class=\"${cls}\">${c.name}</th>`;\r\n    }).join('') + '</tr>';\r\n\r\n  let unitsRowHtml = '<tr class=\"units-row\"><th></th><th>' + ppfgTvdUnit + '</th>' +\r\n    ppfgCols.map(c => `<th>${c.unit || ''}</th>`).join('') + '</tr>';\r\n\r\n  document.getElementById('thPpfg').innerHTML = hdrRow + unitsRowHtml;\r\n\r\n  document.getElementById('tbPpfg').innerHTML = ppfgData.map((r, i) => {\r\n    let html = `<tr><td>${i+1}</td><td class=\"c-tvd\">${r.tvd.toFixed(2)}</td>`;\r\n    for (const c of ppfgCols) {\r\n      const v = r[c.name];\r\n      const cls = isPP(c.name) ? 'c-pp' : isFG(c.name) ? 'c-fg' : '';\r\n      html += `<td class=\"${cls}\">${v != null ? v.toFixed(4) : ''}</td>`;\r\n    }\r\n    return html + '</tr>';\r\n  }).join('');\r\n}\r\n\r\nfunction renderPpfgChart() {\r\n  const ctx = document.getElementById('cvsPpfg').getContext('2d');\r\n  if (ppfgChart) ppfgChart.destroy();\r\n\r\n  const palette = ['#b388ff','#fdd835','#ef5350','#4caf50','#5b8def','#ff9800','#03dac6','#e91e63','#00bcd4','#8bc34a','#ff5722','#9c27b0','#607d8b'];\r\n  const datasets = ppfgCols.map((c, idx) => {\r\n    const data = ppfgData.filter(r => r[c.name] != null && r[c.name] > -900).map(r => ({ x: r[c.name], y: r.tvd }));\r\n    return {\r\n      label: c.name,\r\n      data,\r\n      borderColor: palette[idx % palette.length],\r\n      backgroundColor: 'transparent',\r\n      borderWidth: 1.2,\r\n      pointRadius: 0,\r\n      tension: .1,\r\n      hidden: idx > 6\r\n    };\r\n  });\r\n\r\n  ppfgChart = new Chart(ctx, {\r\n    type: 'line',\r\n    data: { datasets },\r\n    options: {\r\n      responsive: true, maintainAspectRatio: false,\r\n      interaction: { mode: 'nearest', intersect: false },\r\n      plugins: {\r\n        legend: { position: 'right', labels: { color: '#9fa8c7', font: { size: 10, family: 'Inter' }, boxWidth: 12, padding: 8 } },\r\n        tooltip: { backgroundColor: '#1c1f2e', titleColor: '#e8eaf6', bodyColor: '#e8eaf6', borderColor: '#353950', borderWidth: 1 }\r\n      },\r\n      scales: {\r\n        x: { title: { display: true, text: 'Pressure / Gradient (ppg)', color: '#9fa8c7' }, grid: { color: 'rgba(53,57,80,.4)' }, ticks: { color: '#9fa8c7' } },\r\n        y: { reverse: true, title: { display: true, text: 'TVD (ft)', color: '#9fa8c7' }, grid: { color: 'rgba(53,57,80,.4)' }, ticks: { color: '#9fa8c7' } }\r\n      }\r\n    }\r\n  });\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Step 3: Interpolation\r\n   ═══════════════════════════════════════════ */\r\nfunction checkReady() {\r\n  const ready = survey.length >= 2 && ppfgData.length > 0;\r\n  document.getElementById('btnInterp').disabled = !ready;\r\n}\r\n\r\nfunction runInterpolation() {\r\n  if (survey.length < 2) { toast('Load a well plan first (Step 1)', true); return; }\r\n  if (ppfgData.length === 0) { toast('Load PPFG data first (Step 2)', true); return; }\r\n\r\n  results = [];\r\n  for (const row of ppfgData) {\r\n    const res = interpTVDtoMD(row.tvd);\r\n    if (!res) continue;\r\n    const entry = { tvd: row.tvd, md: res.md, inc: res.inc, sMD: res.sMD, sTVD: res.sTVD };\r\n    for (const c of ppfgCols) {\r\n      entry[c.name] = row[c.name];\r\n    }\r\n    results.push(entry);\r\n  }\r\n\r\n  if (results.length === 0) { toast('No valid interpolation results', true); return; }\r\n\r\n  renderResults();\r\n  updateChartPoints();\r\n\r\n  show('interpOk');\r\n  document.getElementById('xIRows').textContent = results.length;\r\n  const mds = results.map(r => r.md);\r\n  document.getElementById('xIMDR').textContent = fmt0(Math.min(...mds)) + '–' + fmt0(Math.max(...mds));\r\n\r\n  markStep(3, 'done');\r\n  updateStatus('Interpolation complete', true);\r\n  document.getElementById('btnUploadCorva').disabled = false;\r\n  goTab('pResults');\r\n  toast(`Interpolated ${results.length} depths with PPFG data`);\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Interpolation Engine\r\n   ═══════════════════════════════════════════ */\r\nfunction interpTVDtoMD(tvd) {\r\n  let stn = survey[0];\r\n  for (const s of survey) {\r\n    if (s.tvd <= tvd) stn = s;\r\n    else break;\r\n  }\r\n  const cosI = Math.cos(stn.inc * Math.PI / 180);\r\n  if (Math.abs(cosI) < 1e-10) return null;\r\n  const md = (tvd - stn.tvd) / cosI + stn.md;\r\n  return { tvd, md, inc: stn.inc, sMD: stn.md, sTVD: stn.tvd };\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Quick Lookup\r\n   ═══════════════════════════════════════════ */\r\nfunction calcOne() {\r\n  if (survey.length < 2) { toast('Load a well plan first', true); return; }\r\n  const v = parseFloat(document.getElementById('qIn').value);\r\n  if (isNaN(v)) { toast('Enter a TVD value', true); return; }\r\n  const r = interpTVDtoMD(v);\r\n  if (!r) { toast('Out of range', true); return; }\r\n\r\n  show('qOut');\r\n  document.getElementById('qMD').textContent = r.md.toFixed(3);\r\n  document.getElementById('qInc').textContent = r.inc.toFixed(2);\r\n  document.getElementById('qStn').innerHTML =\r\n    `Bracketing station: MD = <strong>${r.sMD.toFixed(2)}</strong> ft, TVD = <strong>${r.sTVD.toFixed(3)}</strong> ft, Inc = <strong>${r.inc.toFixed(2)}</strong>&deg;`;\r\n  document.getElementById('qForm').innerHTML =\r\n    `MD = (TVD &minus; TVD<sub>stn</sub>) / cos(Inc) + MD<sub>stn</sub><br>` +\r\n    `MD = (${v.toFixed(2)} &minus; ${r.sTVD.toFixed(3)}) / cos(${r.inc.toFixed(2)}&deg;) + ${r.sMD.toFixed(2)}<br>` +\r\n    `<strong style=\"color:var(--accent)\">MD = ${r.md.toFixed(3)} ft</strong>`;\r\n}\r\ndocument.getElementById('qIn').addEventListener('keydown', e => { if (e.key === 'Enter') calcOne(); });\r\n\r\n/* ═══════════════════════════════════════════\r\n   Results Rendering\r\n   ═══════════════════════════════════════════ */\r\nfunction renderResults() {\r\n  const isPP = name => /ppg|pp_|pore|mud|mw/i.test(name);\r\n  const isFG = name => /fg|frac|lot|obg|bhs|seawater|fp_/i.test(name);\r\n\r\n  let hdrRow = '<tr><th>#</th><th>Depth</th><th>TVDKB</th><th>Inc</th>' +\r\n    ppfgCols.map(c => {\r\n      const cls = isPP(c.name) ? 'th-pp' : isFG(c.name) ? 'th-fg' : '';\r\n      return `<th class=\"${cls}\">${c.name}</th>`;\r\n    }).join('') + '<th>Stn MD</th><th>Stn TVD</th></tr>';\r\n\r\n  let unitsRowHtml = '<tr class=\"units-row\"><th></th><th>FT</th><th>' + ppfgTvdUnit + '</th><th>deg</th>' +\r\n    ppfgCols.map(c => `<th>${c.unit || ''}</th>`).join('') + '<th>FT</th><th>FT</th></tr>';\r\n\r\n  document.getElementById('thResults').innerHTML = hdrRow + unitsRowHtml;\r\n\r\n  document.getElementById('tbResults').innerHTML = results.map((r, i) => {\r\n    let html = `<tr><td>${i+1}</td><td class=\"c-md\">${r.md.toFixed(3)}</td><td class=\"c-tvd\">${r.tvd.toFixed(2)}</td><td class=\"c-inc\">${r.inc.toFixed(2)}</td>`;\r\n    for (const c of ppfgCols) {\r\n      const v = r[c.name];\r\n      const cls = isPP(c.name) ? 'c-pp' : isFG(c.name) ? 'c-fg' : '';\r\n      html += `<td class=\"${cls}\">${v != null ? v.toFixed(4) : ''}</td>`;\r\n    }\r\n    html += `<td>${r.sMD.toFixed(2)}</td><td>${r.sTVD.toFixed(3)}</td></tr>`;\r\n    return html;\r\n  }).join('');\r\n\r\n  show('aResults'); hide('eResults');\r\n  document.getElementById('bResults').textContent = results.length + ' results';\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Chart\r\n   ═══════════════════════════════════════════ */\r\nfunction drawChart() {\r\n  const ctx = document.getElementById('cvs').getContext('2d');\r\n  if (chart) chart.destroy();\r\n  chart = new Chart(ctx, {\r\n    type: 'line',\r\n    data: {\r\n      datasets: [\r\n        {\r\n          label: 'Well Plan (MD vs TVD)', data: surveyByMD.map(s => ({ x: s.md, y: s.tvd })),\r\n          borderColor: 'var(--accent)', backgroundColor: 'rgba(3,218,198,.06)', borderWidth: 1.5,\r\n          pointRadius: 0, fill: true, tension: .1\r\n        },\r\n        {\r\n          label: 'Interpolated Points', data: [],\r\n          borderColor: 'transparent', backgroundColor: '#ff9800',\r\n          pointRadius: 4, pointStyle: 'circle', showLine: false\r\n        }\r\n      ]\r\n    },\r\n    options: {\r\n      responsive: true, maintainAspectRatio: false,\r\n      interaction: { mode: 'nearest', intersect: false },\r\n      plugins: {\r\n        legend: { labels: { color: '#9fa8c7', font: { size: 11, family: 'Inter' } } },\r\n        tooltip: {\r\n          backgroundColor: '#1c1f2e', titleColor: '#e8eaf6', bodyColor: '#e8eaf6',\r\n          borderColor: '#353950', borderWidth: 1,\r\n          callbacks: { label: c => `MD: ${c.raw.x.toFixed(1)} ft | TVD: ${c.raw.y.toFixed(1)} ft` }\r\n        }\r\n      },\r\n      scales: {\r\n        x: { title: { display: true, text: 'Measured Depth (ft)', color: '#9fa8c7' }, grid: { color: 'rgba(53,57,80,.4)' }, ticks: { color: '#9fa8c7' } },\r\n        y: { title: { display: true, text: 'True Vertical Depth (ft)', color: '#9fa8c7' }, grid: { color: 'rgba(53,57,80,.4)' }, ticks: { color: '#9fa8c7' } }\r\n      }\r\n    }\r\n  });\r\n}\r\n\r\nfunction updateChartPoints() {\r\n  if (!chart) return;\r\n  chart.data.datasets[1].data = results.map(r => ({ x: r.md, y: r.tvd }));\r\n  chart.update();\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Export\r\n   ═══════════════════════════════════════════ */\r\nfunction expSurveyCSV() {\r\n  dl('MD,Inc,Azm,TVD\\n' + surveyByMD.map(s => `${s.md},${s.inc},${s.azm},${s.tvd}`).join('\\n'), 'survey.csv', 'text/csv');\r\n}\r\n\r\nfunction expPpfgCSV() {\r\n  const hdr = ['TVD', ...ppfgCols.map(c => c.name)].join(',');\r\n  const units = [ppfgTvdUnit, ...ppfgCols.map(c => c.unit || '')].join(',');\r\n  const rows = ppfgData.map(r => [r.tvd, ...ppfgCols.map(c => r[c.name] ?? '')].join(',')).join('\\n');\r\n  dl(hdr + '\\n' + units + '\\n' + rows, 'ppfg_data.csv', 'text/csv');\r\n}\r\n\r\nfunction getExportName() {\r\n  return (document.getElementById('corvaFileName').value.trim() || 'ppfg_interpolated').replace(/\\.[^.]+$/, '');\r\n}\r\n\r\nfunction expResultsCSV() {\r\n  const hdr = ['Depth', 'TVDKB', ...ppfgCols.map(c => c.name)].join(',');\r\n  const units = ['FT', ppfgTvdUnit, ...ppfgCols.map(c => c.unit || '')].join(',');\r\n  const rows = results.map(r => [r.md, r.tvd, ...ppfgCols.map(c => r[c.name] ?? '')].join(',')).join('\\n');\r\n  dl(hdr + '\\n' + units + '\\n' + rows, getExportName() + '.csv', 'text/csv');\r\n}\r\n\r\nfunction expResultsXLSX() {\r\n  const name = getExportName();\r\n  const header = ['Depth', 'TVDKB', ...ppfgCols.map(c => c.name)];\r\n  const units = ['FT', ppfgTvdUnit, ...ppfgCols.map(c => c.unit || '')];\r\n  const rows = [header, units];\r\n  results.forEach(r => {\r\n    rows.push([r.md, r.tvd, ...ppfgCols.map(c => r[c.name] ?? '')]);\r\n  });\r\n  const ws = XLSX.utils.aoa_to_sheet(rows);\r\n  ws['!cols'] = header.map(() => ({ wch: 16 }));\r\n  const wb = XLSX.utils.book_new();\r\n  XLSX.utils.book_append_sheet(wb, ws, name);\r\n  XLSX.writeFile(wb, name + '.xlsx');\r\n}\r\n\r\nfunction dl(txt, name, type) {\r\n  const a = document.createElement('a');\r\n  a.href = URL.createObjectURL(new Blob([txt], { type }));\r\n  a.download = name;\r\n  document.body.appendChild(a); a.click(); document.body.removeChild(a);\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Upload to Corva\r\n   ═══════════════════════════════════════════ */\r\nfunction getCorvaDataAPI() {\r\n  try {\r\n    const mod = window.corvaDataAPI;\r\n    if (mod && typeof mod.post === 'function') return mod;\r\n  } catch (e) {}\r\n  return null;\r\n}\r\n\r\nasync function uploadToCorva() {\r\n  const assetId = +document.getElementById('corvaAssetId').value;\r\n  const logId = document.getElementById('corvaLogId').value.trim() || getExportName();\r\n  const provider = document.getElementById('corvaProvider').value.trim() || 'corva';\r\n  const dataset = document.getElementById('corvaDataset').value.trim() || 'drilling.wits.depth';\r\n\r\n  if (!assetId || isNaN(assetId)) { toast('Enter a valid Well Asset ID', true); return; }\r\n  if (results.length === 0) { toast('Run interpolation first (Step 3)', true); return; }\r\n\r\n  const api = getCorvaDataAPI();\r\n  if (!api) { toast('Corva Data API not available — run this app inside Corva Dev Center', true); return; }\r\n\r\n  const btn = document.getElementById('btnUploadCorva');\r\n  btn.disabled = true;\r\n  btn.textContent = 'Uploading...';\r\n\r\n  const BATCH_SIZE = 500;\r\n  const records = results.map(r => {\r\n    const data = {};\r\n    for (const c of ppfgCols) {\r\n      data[c.name] = r[c.name] ?? null;\r\n    }\r\n    data.tvd = r.tvd;\r\n    return {\r\n      asset_id: assetId,\r\n      measured_depth: r.md,\r\n      log_identifier: logId,\r\n      data\r\n    };\r\n  });\r\n\r\n  const path = `/api/v1/data/${provider}/${dataset}/`;\r\n  let uploaded = 0;\r\n\r\n  try {\r\n    for (let i = 0; i < records.length; i += BATCH_SIZE) {\r\n      const batch = records.slice(i, i + BATCH_SIZE);\r\n      await api.post(path, batch);\r\n      uploaded += batch.length;\r\n      btn.textContent = `Uploading... ${uploaded}/${records.length}`;\r\n    }\r\n\r\n    show('corvaUploadStatus');\r\n    document.getElementById('xUpRows').textContent = uploaded;\r\n    document.getElementById('xUpStatus').textContent = 'OK';\r\n    document.getElementById('xUpStatus').style.color = 'var(--green)';\r\n    toast(`Uploaded ${uploaded} records to Corva`);\r\n  } catch (err) {\r\n    failed = true;\r\n    show('corvaUploadStatus');\r\n    document.getElementById('xUpRows').textContent = uploaded;\r\n    document.getElementById('xUpStatus').textContent = 'Error';\r\n    document.getElementById('xUpStatus').style.color = 'var(--red)';\r\n    toast(`Upload failed: ${err.message}`, true);\r\n  } finally {\r\n    btn.disabled = false;\r\n    btn.textContent = 'Upload to Corva Logs';\r\n  }\r\n}\r\n\r\n/* ═══════════════════════════════════════════\r\n   Utilities\r\n   ═══════════════════════════════════════════ */\r\nfunction getHeaders(wb, sheet, hdrRow) {\r\n  const ws = wb.Sheets[sheet];\r\n  if (!ws) return { headers: [], detectedRow: hdrRow - 1 };\r\n  const rng = XLSX.utils.decode_range(ws['!ref']);\r\n\r\n  const bestRow = findBestHeaderRow(ws, rng, hdrRow - 1);\r\n\r\n  const out = [];\r\n  for (let c = rng.s.c; c <= rng.e.c; c++) {\r\n    const a = XLSX.utils.encode_cell({ r: bestRow, c });\r\n    const cell = ws[a];\r\n    const lbl = cell ? String(cell.v || '').trim() : '';\r\n    out.push({ c, lbl: lbl || `Col ${XLSX.utils.encode_col(c)}`, letter: XLSX.utils.encode_col(c) });\r\n  }\r\n  return { headers: out, detectedRow: bestRow };\r\n}\r\n\r\nfunction findBestHeaderRow(ws, rng, requestedRow) {\r\n  const maxScan = Math.min(requestedRow + 10, rng.e.r);\r\n  let best = requestedRow, bestScore = 0;\r\n\r\n  for (let r = requestedRow; r <= maxScan; r++) {\r\n    let textCols = 0, totalCols = 0;\r\n    for (let c = rng.s.c; c <= rng.e.c; c++) {\r\n      const cell = ws[XLSX.utils.encode_cell({ r, c })];\r\n      if (!cell) continue;\r\n      totalCols++;\r\n      const v = String(cell.v || '').trim();\r\n      if (v && isNaN(Number(v))) textCols++;\r\n    }\r\n    if (totalCols === 0) continue;\r\n    const score = textCols / totalCols;\r\n    if (score > bestScore) { bestScore = score; best = r; }\r\n  }\r\n  return best;\r\n}\r\n\r\nfunction fillSel(id, hdrs, pats, optional) {\r\n  const sel = document.getElementById(id);\r\n  sel.innerHTML = optional ? '<option value=\"\">-- None --</option>' : '<option value=\"\">-- Select --</option>';\r\n  hdrs.forEach(h => { const o = document.createElement('option'); o.value = h.c; o.textContent = `${h.letter}: ${h.lbl}`; sel.appendChild(o); });\r\n  if (pats) {\r\n    const lp = pats.map(p => p.toLowerCase());\r\n    for (const h of hdrs) {\r\n      const l = h.lbl.toLowerCase();\r\n      if (lp.some(p => l.includes(p) || l === p)) { sel.value = h.c; break; }\r\n    }\r\n  }\r\n}\r\n\r\nfunction parseNameUnit(raw) {\r\n  const m = raw.match(/^(.+?)\\s*\\[([^\\]]+)\\]\\s*$/);\r\n  if (m) return { name: m[1].trim(), unit: m[2].trim() };\r\n  const m2 = raw.match(/^(.+?)\\s*\\(([^)]+)\\)\\s*$/);\r\n  if (m2) return { name: m2[1].trim(), unit: m2[2].trim() };\r\n  return { name: raw, unit: '' };\r\n}\r\n\r\nfunction cellNum(ws, r, c) {\r\n  const a = XLSX.utils.encode_cell({ r, c });\r\n  const cell = ws[a];\r\n  if (!cell) return null;\r\n  const v = typeof cell.v === 'number' ? cell.v : parseFloat(cell.v);\r\n  return isNaN(v) ? null : v;\r\n}\r\n\r\nfunction cellStr(ws, r, c) {\r\n  const a = XLSX.utils.encode_cell({ r, c });\r\n  const cell = ws[a];\r\n  return cell ? String(cell.v || '') : null;\r\n}\r\n\r\nfunction fmt0(n) { return Math.round(n).toLocaleString(); }\r\nfunction show(id) { document.getElementById(id).style.display = 'block'; }\r\nfunction hide(id) { document.getElementById(id).style.display = 'none'; }\r\n\r\n/* Tabs */\r\nfunction goTab(id) {\r\n  document.querySelectorAll('.main-content > .tpane').forEach(p => p.classList.remove('on'));\r\n  document.querySelectorAll('.main-content > .main-tabs:first-child .main-tab').forEach(t => t.classList.remove('on'));\r\n  document.getElementById(id).classList.add('on');\r\n  const map = ['pChart', 'pSurvey', 'pPpfg', 'pResults'];\r\n  const idx = map.indexOf(id);\r\n  if (idx >= 0) document.querySelectorAll('.main-content > .main-tabs')[0].querySelectorAll('.main-tab')[idx].classList.add('on');\r\n}\r\n\r\nfunction goPpfgSub(id) {\r\n  ['ppfgTable', 'ppfgChart'].forEach(n => {\r\n    document.getElementById(n).classList.remove('on');\r\n  });\r\n  document.querySelectorAll('#aPpfg .main-tabs .main-tab').forEach(t => t.classList.remove('on'));\r\n  document.getElementById(id).classList.add('on');\r\n  const idx = id === 'ppfgTable' ? 0 : 1;\r\n  document.querySelectorAll('#aPpfg .main-tabs .main-tab')[idx].classList.add('on');\r\n  if (id === 'ppfgChart' && ppfgChart) ppfgChart.resize();\r\n}\r\n\r\n/* Steps */\r\nfunction markStep(n, state) {\r\n  const el = document.getElementById('step' + n);\r\n  el.classList.remove('active', 'done');\r\n  if (state === 'done') el.classList.add('done');\r\n  if (state === 'active') el.classList.add('active');\r\n}\r\n\r\n/* Status */\r\nfunction updateStatus(msg, ok) {\r\n  document.getElementById('statusText').textContent = msg;\r\n  document.getElementById('statusDot').style.background = ok ? 'var(--green)' : 'var(--dim)';\r\n}\r\n\r\n/* Toast */\r\nfunction toast(msg, err) {\r\n  const t = document.getElementById('toast');\r\n  t.textContent = msg;\r\n  t.className = 'toast on' + (err ? ' err' : '');\r\n  clearTimeout(t._tm);\r\n  t._tm = setTimeout(() => t.className = 'toast', 3000);\r\n}\r\n</script>\r\n</body>\r\n</html>\r\n";
export default htmlContent;
